function solve(s) {
    const n = s.length;
    let maxLen = 0;

    // Helper function to find the longest balanced substring in a given string t
    const findLongestBalancedSubstring = (t) => {
        const len = t.length;
        let currentMax = 0;
        // Prefix sums approach: balance[i] = count('1') - count('0') in t[0...i-1]
        // A substring t[i...j-1] is balanced if count('1') == count('0'),
        // which means prefix_sum[j] - prefix_sum[i] == 0, or prefix_sum[j] == prefix_sum[i].
        const balanceMap = new Map();
        balanceMap.set(0, -1); // Key: balance value, Value: smallest index i such that balance[i] = value
        let currentBalance = 0;
        let localMax = 0;

        for (let j = 0; j < len; j++) {
            if (t[j] === '1') {
                currentBalance++;
            } else {
                currentBalance--;
            }

            if (balanceMap.has(currentBalance)) {
                // Found a previous index i such that balance[i] == balance[j+1]
                const i = balanceMap.get(currentBalance);
                // Length is (j+1) - i
                localMax = Math.max(localMax, j - i);
            } else {
                // Store the first occurrence index (j) corresponding to this balance
                balanceMap.set(currentBalance, j);
            }
        }
        return localMax;
    };

    // Case 1: No swap (0 swaps)
    maxLen = findLongestBalancedSubstring(s);

    // Case 2: One swap
    // Iterate over all possible pairs of indices (i, j) to swap. O(N^2) pairs.
    // Since N <= 10^5, an O(N^2) approach will TLE.
    // We need a more efficient approach than O(N^3) total complexity (N^2 swaps * N substring check).

    // The core problem is: what is the maximum length of a balanced substring
    // after at most one swap?

    // A balanced substring S[l..r] must have count('0') = count('1').
    // The maximum length is 2 * min(count('0'), count('1')) in that substring.

    // Let's analyze the effect of a single swap: s[i] <-> s[j].

    // If we don't swap, maxLen is already calculated.

    // If we swap, we are looking for a balanced substring S'[l..r] in the modified string S'.
    // The length of S'[l..r] is r - l + 1.

    // If the target substring S'[l..r] does not include i or j, the balance is unchanged.
    // If it includes only one of i or j, the balance might change by +/- 2 (if the swapped characters are different).
    // If it includes both i and j, the balance change depends on s[i], s[j], and the original positions.

    // Given N up to 10^5, we must aim for O(N^2) or better. O(N^2) is likely too slow if the check inside is O(N).
    // A full O(N^3) check is out.

    // Re-evaluating the constraint: The total length is 10^5.
    // Let's try to fix the substring [l, r] and check if one swap can balance it.

    // For a fixed substring S[l..r]:
    // Let count0 and count1 be the counts in S[l..r].
    // The length is L = count0 + count1.
    // We need the final counts to be L/2 each.
    // If L is odd, it cannot be balanced.
    // If L is even, we need |count0 - count1| to be 0.

    // If count0 != count1, let diff = |count0 - count1|.
    // We need to change the difference by 'diff' using one swap involving indices i, j, where l <= i, j <= r.

    // Case 1: Swap involves two characters INSIDE [l, r] (i, j in [l, r]).
    // - Swap '0' at i and '1' at j (if available).
    //   count0 decreases by 1, count1 increases by 1. New difference reduces by 2.
    // - Swap '1' at i and '0' at j. New difference reduces by 2.
    // We can reduce the difference by 2 if we can find a pair of differing characters inside the range.
    // If |count0 - count1| = 2, and count0 > count1 (need one more '1'), we need to swap a '0' with a '1' inside. If we have both, we fix it.
    // If |count0 - count1| is even, say 2k, we need k swaps, but we only have 1.

    // With one swap inside [l, r]:
    // If we swap 0 <-> 1, the difference changes by 2.
    // If we swap 0 <-> 0 or 1 <-> 1, the difference is unchanged.
    // Maximum change in difference is 2.
    // Therefore, if the original difference |count0 - count1| > 2, no internal swap fixes it.
    // If |count0 - count1| = 2, we need to swap a differing pair (0/1). If one exists, it's balanced.
    // If |count0 - count1| = 0, it's already balanced (maxLen already covers this).

    // Case 2: Swap involves one character inside [l, r] (i in [l, r]) and one outside (j outside [l, r]).
    // - Swap s[i]='0' with s[j]='1' (j outside).
    //   Inside [l, r]: count0 -> count0-1, count1 -> count1+1. Difference reduces by 2.
    // - Swap s[i]='1' with s[j]='0' (j outside).
    //   Inside [l, r]: count0 -> count0+1, count1 -> count1-1. Difference reduces by 2.

    // Conclusion: After at most one swap, the difference in counts within any substring can change by at most 2.
    // If the initial difference is D, the final difference D' must satisfy |D'| <= |D| + 2. (Wait, this is wrong).
    // The change in difference $\Delta D$ is bounded by 2 if the swap is internal, and potentially larger if one character is outside.

    // Let $D = C_1 - C_0$ in $S[l..r]$.
    // Swap $S[i]$ and $S[j]$.
    // 1. $i, j \in [l, r]$. $\Delta D \in \{-2, 0, 2\}$. Max change = 2.
    // 2. $i \in [l, r], j \notin [l, r]$.
    //    - $S[i]=0, S[j]=1$. New $S'[i]=1$. $C_1 \to C_1+1, C_0 \to C_0-1$. $\Delta D = +2$.
    //    - $S[i]=1, S[j]=0$. New $S'[i]=0$. $C_1 \to C_1-1, C_0 \to C_0+1$. $\Delta D = -2$.
    // 3. $i, j \notin [l, r]$. $\Delta D = 0$.

    // The maximum change in balance (count1 - count0) for $S[l..r]$ due to one swap is $\pm 2$.
    // Therefore, a substring $S[l..r]$ can become balanced if and only if its initial balance $D$ satisfies $|D| \le 2$.

    // We iterate over all $O(N^2)$ substrings, calculate $D$, and if $|D| \le 2$, update maxLen.
    // $N=10^5$, $O(N^2)$ is $10^{10}$, too slow.

    // We must use the prefix sum approach for O(N^2) check, but we need an O(N) or O(N log N) solution.

    // --- Final attempt based on prefix sums and restricted difference ---
    // Let $P[k]$ be the prefix balance up to index $k-1$. $P[0]=0$.
    // $S[l..r]$ is balanced if $P[r+1] - P[l] = 0$.
    // After swap, the new prefix balances $P'$ might change.

    // If we swap $S[i] \leftrightarrow S[j]$, the balance changes only in the segments starting after $\min(i, j)$ up to $N$.
    // Let $k = \min(i, j)$ and $m = \max(i, j)$.
    // For $k < x \le m$: $P'[x] = P[x] + \Delta$. ($\Delta$ is $+2$ or $-2$ depending on the swap).
    // For $x > m$: $P'[x] = P[x] + 2\Delta$.

    // This complexity seems too high for a standard contest setting unless there is a very clever structural insight missed.
    // Given the constraints ($N=10^5$), the solution must be $O(N)$ or $O(N \log N)$.

    // Re-read the problem: "You can perform AT MOST one swap."

    // The only way to achieve $O(N)$ is if the maximum balanced substring must satisfy some strong property related to the original structure.
    // If the maximum length is $L$, it means there exists a swap and a substring of length $L$.

    // If $L$ is large, say $L \approx N$, the difference $D$ must be close to 0.

    // Let's trust the property derived: A substring $S[l..r]$ can be balanced if and only if $|D| \le 2$, provided we can choose the swap optimally (internal or external). Since external swaps only change $D$ by $\pm 2$, and internal swaps change $D$ by $\{-2, 0, 2\}$, the condition remains $|D| \le 2$ for *some* swap to make it balanced.

    // Since $O(N^2)$ iteration is too slow, we must check only the $O(N)$ candidates implied by the prefix sum approach.

    // We are looking for $l, r$ such that $P[r+1] - P[l] \in \{-2, -1, 0, 1, 2\}$.
    // This means $P[r+1] - P[l] = d$, where $d \in \{-2, -1, 0, 1, 2\}$.
    // Or $P[l] = P[r+1] - d$.

    // We iterate $r+1$ from $1$ to $N$. For each $P[r+1]$, we check for the existence of $P[l]$ such that $P[l] \in \{P[r+1] - 2, P[r+1] - 1, P[r+1], P[r+1] + 1, P[r+1] + 2\}$ and $l < r+1$.
    // To maximize $r+1 - l$, we need the smallest possible $l$.

    // We use a map to store the *smallest* index $l$ seen so far for each prefix sum value $P[l]$.

    const prefixBalance = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixBalance[i + 1] = prefixBalance[i] + (s[i] === '1' ? 1 : -1);
    }

    // Map: balance value -> smallest index l such that prefixBalance[l] = balance
    const minIndexForBalance = new Map();
    // Initialize with index 0 (representing the empty prefix)
    minIndexForBalance.set(0, 0);

    maxLen = 0; // Already initialized to cover 0 swaps

    // Iterate over end points r+1 (from 1 to N)
    for (let j = 1; j <= n; j++) {
        const currentP = prefixBalance[j];

        // Check for balances d in {-2, -1, 0, 1, 2}
        for (let d = -2; d <= 2; d++) {
            const targetP = currentP - d;

            if (minIndexForBalance.has(targetP)) {
                const l = minIndexForBalance.get(targetP);
                // Found a substring S[l..j-1] with balance d.
                // If d=0, it's balanced without swap.
                // If |d| <= 2, it can be balanced with one swap.
                maxLen = Math.max(maxLen, j - l);
            }
        }

        // Update the map with the current index j, only if it's the first time we see this balance
        if (!minIndexForBalance.has(currentP)) {
            minIndexForBalance.set(currentP, j);
        }
    }

    // The empty string is always balanced, length 0. maxLen starts at 0 and handles this.

    return maxLen;
}

