fn solve(s: String) -> i64 {
    let n = s.len();
    if n == 0 {
        return 0;
    }

    // Calculate prefix balances. balance[i] is the balance (count('1') - count('0')) 
    // for the prefix s[0..i-1]. balance[0] = 0.
    let mut prefix_balance = vec![0; n + 1];
    for i in 0..n {
        let value = if s.as_bytes()[i] == b'1' { 1 } else { -1 };
        prefix_balance[i + 1] = prefix_balance[i] + value;
    }

    // Map: balance value -> smallest index l such that prefix_balance[l] = balance
    // We use a HashMap because the balance values can range from -N to N.
    let mut min_index_for_balance: std::collections::HashMap<i32, usize> = 
        std::collections::HashMap::new();

    // Initialize with index 0 (representing the empty prefix)
    min_index_for_balance.insert(0, 0);

    let mut max_len: i64 = 0;

    // Iterate over end points j (from 1 to N). j corresponds to the index *after* the substring ends.
    for j in 1..=n {
        let current_p = prefix_balance[j];

        // A substring S[l..j-1] has balance d = prefix_balance[j] - prefix_balance[l].
        // The substring can be made balanced if |d| <= 2.
        // This means prefix_balance[l] must be in {current_p - 2, ..., current_p + 2}.

        // We check for required previous balances P[l] = current_P - d, where d in {-2, -1, 0, 1, 2}
        for d in -2..=2 {
            let target_p = current_p - d;

            if let Some(&l) = min_index_for_balance.get(&target_p) {
                // Found a substring S[l..j-1] whose balance is d. 
                // Since |d| <= 2, this substring can be made balanced by at most one swap.
                let current_len = (j - l) as i64;
                if current_len > max_len {
                    max_len = current_len;
                }
            }
        }

        // Update the map with the current index j, storing the smallest index for current_p.
        // Since we iterate j in increasing order, we only insert if it's not already present,
        // ensuring we keep the smallest possible l for any future calculations.
        min_index_for_balance.entry(current_p).or_insert(j);
    }

    max_len
}
