use std::collections::HashMap;

fn solve(s: String) -> i64 {
    let n = s.len();
    if n == 0 {
        return 0;
    }

    // prefix_balance[i] stores the balance (count('1') - count('0')) of s[0...i-1]
    // Size N+1, indices 0 to N.
    let mut prefix_balance = vec![0; n + 1];
    for i in 0..n {
        let change = if s.as_bytes()[i] == b'1' { 1 } else { -1 };
        prefix_balance[i + 1] = prefix_balance[i] + change;
    }

    // min_index_for_balance: maps balance value -> smallest index l such that prefix_balance[l] = balance
    let mut min_index_for_balance: HashMap<i32, usize> = HashMap::new();
    // Initialize with index 0 (representing the empty prefix)
    min_index_for_balance.insert(0, 0);

    let mut max_len: i64 = 0;

    // Iterate over end points j (from 1 to N), representing the end of the prefix s[0...j-1]
    for j in 1..=n {
        let current_p = prefix_balance[j];

        // We are looking for a starting index l < j such that the substring s[l..j-1]
        // can be made balanced by at most one swap.
        // This happens if the initial balance D = current_p - prefix_balance[l] satisfies |D| <= 2.
        // D = current_p - P[l]  =>  P[l] = current_p - D
        // We check D in {-2, -1, 0, 1, 2}.
        for d in -2..=2 {
            let target_p = current_p - d;

            if let Some(&l) = min_index_for_balance.get(&target_p) {
                // Found a potential start index l.
                // Length of substring is j - l.
                let current_len = (j - l) as i64;
                if current_len > max_len {
                    max_len = current_len;
                }
            }
        }

        // Update the map with the current index j, only if it's the first time we see this balance
        // We only store the smallest index to maximize the length j - l later.
        min_index_for_balance.entry(current_p).or_insert(j);
    }

    max_len
}
