fn solve(s: String) -> i64 {
    let n = s.len();
    if n == 0 {
        return 0;
    }

    // prefix_balance[i] stores the balance ('1' count - '0' count) of s[0..i-1].
    // Size is n + 1. prefix_balance[0] = 0.
    let mut prefix_balance = vec![0; n + 1];
    for i in 0..n {
        let value = if s.as_bytes()[i] == b'1' { 1 } else { -1 };
        prefix_balance[i + 1] = prefix_balance[i] + value;
    }

    // max_len stores the result, initialized to 0 (empty substring).
    let mut max_len: i64 = 0;

    // min_index_for_balance maps a balance value P to the smallest index l 
    // such that prefix_balance[l] == P.
    let mut min_index_for_balance: std::collections::HashMap<i32, usize> = std::collections::HashMap::new();

    // Initialize with index 0 (the empty prefix)
    min_index_for_balance.insert(0, 0);

    // Iterate over end points j (where j = r+1, from 1 to N)
    for j in 1..=n {
        let current_p = prefix_balance[j];

        // We check for previous indices l (l < j) such that the balance of s[l..j-1]
        // is d, where d can be in {-2, -1, 0, 1, 2}.
        // This means prefix_balance[j] - prefix_balance[l] = d, or 
        // prefix_balance[l] = prefix_balance[j] - d.
        for d in -2..=2 {
            let target_p = (current_p - d) as i32;

            if let Some(&l) = min_index_for_balance.get(&target_p) {
                // The substring s[l..j-1] has a balance d, so it can be made balanced
                // with at most one swap.
                let current_len = (j - l) as i64;
                max_len = max_len.max(current_len);
            }
        }

        // Update the map with the current index j, only if it's the first time we see this balance
        if !min_index_for_balance.contains_key(&current_p) {
            min_index_for_balance.insert(current_p, j);
        }
    }

    max_len
}
